// Group per-minute anomaly rows by (router_ip, local_device_name)
// and emit an alarm when high- or low-anomaly count crosses the threshold.
function handler(input) {
  var HIGH = 2, LOW = 2;
  var results = (input && input.anomaly_results) || [];
  var groups = {};
  for (var i = 0; i < results.length; i++) {
    var r = results[i];
    var key = (r.router_ip || '') + '|' + (r.local_device_name || '');
    if (!groups[key]) {
      groups[key] = { router_ip: r.router_ip, local_device_name: r.local_device_name, high_count: 0, low_count: 0 };
    }
    if (r.anomaly_flag === 'high_anomaly') groups[key].high_count += 1;
    else if (r.anomaly_flag === 'low_anomaly') groups[key].low_count += 1;
  }
  var now = (new Date()).toISOString();
  var alarms = [];
  for (var k in groups) {
    var g = groups[k];
    if (g.high_count >= HIGH || g.low_count >= LOW) {
      alarms.push({ created_at: now, router_ip: g.router_ip, local_device_name: g.local_device_name, high_count: g.high_count, low_count: g.low_count });
    }
  }
  return { alarms: alarms };
}
